SELECT DISTINCT
    peh.PAT_ENC_CSN_ID
    , pat.PAT_MRN_ID "MRN"
    , pat.PAT_NAME "Patient Name"
    , FLOOR((peh.ADT_ARRIVAL_TIME - pat.BIRTH_DATE) / 365.25) "Age at Encounter"
    , peh.HOSP_ADMSN_TIME "Admission Date"
    , dep.DEPARTMENT_NAME "Admission Dept"
    , zc_et.NAME "Admission or Transfer"
    , edg.DX_ID "DX ID"
    , ped.PRIMARY_DX_YN "Primary Dx?"
    , edg.CURRENT_ICD10_LIST "ICD10 Code"
    , edg.DX_NAME "Dx Name"

FROM CLARITY_ADT adt
    INNER JOIN PAT_ENC_HSP peh ON adt.PAT_ENC_CSN_ID = peh.PAT_ENC_CSN_ID
    INNER JOIN CLARITY_DEP dep ON adt.DEPARTMENT_ID = dep.DEPARTMENT_ID
    INNER JOIN PATIENT pat ON peh.PAT_ID = pat.PAT_ID
    LEFT OUTER JOIN PAT_ENC_DX ped ON peh.PAT_ENC_CSN_ID = ped.PAT_ENC_CSN_ID
    LEFT OUTER JOIN CLARITY_EDG edg ON ped.DX_ID = edg.DX_ID
    INNER JOIN ZC_EVENT_TYPE zc_et ON adt.EVENT_TYPE_C = zc_et.EVENT_TYPE_C

--FROM PAT_ENC_HSP peh
--    INNER JOIN CLARITY_ADT adt ON peh.ADM_EVENT_ID = adt.EVENT_ID
--    INNER JOIN CLARITY_DEP dep ON adt.DEPARTMENT_ID = dep.DEPARTMENT_ID
--    INNER JOIN PATIENT pat ON peh.PAT_ID = pat.PAT_ID
--    LEFT OUTER JOIN PAT_ENC_DX ped ON peh.PAT_ENC_CSN_ID = ped.PAT_ENC_CSN_ID
--    LEFT OUTER JOIN CLARITY_EDG edg ON ped.DX_ID = edg.DX_ID

WHERE
    peh.HOSP_ADMSN_TIME > '01-SEP-2019'
    AND (FLOOR((peh.ADT_ARRIVAL_TIME - pat.BIRTH_DATE) / 365.25)) < 19
    AND adt.EVENT_TYPE_C IN (1,3)
